import React, { useId } from "react";

/**
 * LevelBadge
 * -----------
 * Component huy hiệu (badge) thể hiện 4 cấp độ, chuyển đổi trực tiếp từ 4 file
 * Frame_1.svg .. Frame_4.svg. Có thể dùng theo 2 cách:
 *   1) Truyền thẳng `level` (1 | 2 | 3 | 4) để chỉ định cấp độ.
 *   2) Truyền `score` (điểm số) để component tự tính ra cấp độ dựa trên
 *      `thresholds` (ngưỡng điểm), mặc định là [50, 75, 90]:
 *        - score < 50            -> cấp 1
 *        - 50  <= score < 75      -> cấp 2
 *        - 75  <= score < 90      -> cấp 3
 *        - score >= 90            -> cấp 4
 *
 * Nếu cả `level` lẫn `score` đều được truyền, `score` sẽ được ưu tiên dùng
 * để tính cấp độ.
 */

export type LevelBadgeLevel = 1 | 2 | 3 | 4;

export interface LevelBadgeProps {
  /** Cấp độ hiển thị trực tiếp (bỏ qua nếu có `score`). Mặc định: 1 */
  level?: LevelBadgeLevel;
  /** Điểm số. Nếu truyền vào, cấp độ sẽ được tự động tính từ điểm số này. */
  score?: number;
  /** Ngưỡng điểm để quy đổi ra cấp độ 2, 3, 4. Mặc định: [50, 75, 90] */
  thresholds?: [number, number, number];
  /** Kích thước hiển thị (chiều rộng, px). Chiều cao tự tính theo tỉ lệ gốc. Mặc định: 120 */
  size?: number;
  /** Nhãn tuỳ chỉnh, mặc định lấy theo `LEVEL_LABELS[level]` */
  label?: string;
  /** Có hiển thị nhãn cấp độ bên dưới badge không. Mặc định: true */
  showLabel?: boolean;
  /** Có hiển thị điểm số bên dưới badge không. Mặc định: true nếu có `score` */
  showScore?: boolean;
  /** Đơn vị hiển thị sau điểm số. Mặc định: "điểm" */
  scoreSuffix?: string;
  className?: string;
  style?: React.CSSProperties;
  labelStyle?: React.CSSProperties;
  scoreStyle?: React.CSSProperties;
}

/** Tên mặc định cho từng cấp độ — có thể ghi đè qua prop `label` hoặc truyền map riêng khi dùng. */
export const LEVEL_LABELS: Record<LevelBadgeLevel, string> = {
  1: "Cấp 1",
  2: "Cấp 2",
  3: "Cấp 3",
  4: "Cấp 4",
};

/** Kích thước gốc (viewBox) của từng SVG nguồn, dùng để giữ đúng tỉ lệ khi scale theo `size`. */
const BADGE_INTRINSIC_SIZE: Record<LevelBadgeLevel, { width: number; height: number }> = {
  1: { width: 164, height: 150 },
  2: { width: 164, height: 150 },
  3: { width: 201, height: 150 },
  4: { width: 201, height: 171 },
};

const DEFAULT_THRESHOLDS: [number, number, number] = [50, 75, 90];

/** Tính cấp độ (1-4) từ điểm số dựa trên ngưỡng `thresholds`. */
export function getLevelFromScore(
  score: number,
  thresholds: [number, number, number] = DEFAULT_THRESHOLDS
): LevelBadgeLevel {
  const [t1, t2, t3] = thresholds;
  if (score >= t3) return 4;
  if (score >= t2) return 3;
  if (score >= t1) return 2;
  return 1;
}

