const LEVEL_SVGS: Record<LevelBadgeLevel, (props: { uid: string }) => React.JSX.Element> = {
  1: Level1Svg,
  2: Level2Svg,
  3: Level3Svg,
  4: Level4Svg,
};

export function LevelBadge({
  level = 1,
  score,
  thresholds,
  size = 120,
  label,
  showLabel = true,
  showScore,
  scoreSuffix = "điểm",
  className,
  style,
  labelStyle,
  scoreStyle,
}: LevelBadgeProps) {
  const uid = useId();

  const resolvedLevel: LevelBadgeLevel =
    score !== undefined ? getLevelFromScore(score, thresholds) : level ?? 1;

  const intrinsic = BADGE_INTRINSIC_SIZE[resolvedLevel];
  const displayWidth = size;
  const displayHeight = (intrinsic.height / intrinsic.width) * size;

  const badgeLabel = label ?? LEVEL_LABELS[resolvedLevel];
  const shouldShowScore = showScore ?? score !== undefined;

  const SvgComponent = LEVEL_SVGS[level];

  return (
    <div
      className={className}
      style={{
        display: "inline-flex",
        flexDirection: "column",
        alignItems: "center",
        gap: 4,
        ...style,
      }}
    >
      <div style={{ width: displayWidth, height: displayHeight, flexShrink: 0 }}>
        <SvgComponent uid={uid} />
      </div>
    </div>
  );
}